#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=5005,mod=80112002;
struct node {
	vector<int> e;
	int cd,rd,b,fas;
} v[maxn];
int n,m,ans;
queue<int> q;
int work(int x) {
	if(v[x].cd==0) {
		return 1;
	}
	if(v[x].fas==0) {
		for(auto e:v[x].e) {
			v[x].fas=(work(e)+v[x].fas)%mod;
		}
	}
	return v[x].fas;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1,x,y; i<=m; i++) {
		cin>>x>>y;
		v[x].e.emplace_back(y);
		v[y].rd++;
		v[x].cd++;
	}
	for(int i=1; i<=n; i++) {
		if(v[i].rd==0) {
			ans=(work(i)+ans)%mod;
		}
	}
	cout<<ans;
	return 0;
}
